import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Row, 
  Text, 
  Divider, 
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  conditionIcon?: string;
  humidity?: number;
  windSpeed?: string;
  unit?: 'C' | 'F';
  forecast?: ForecastDay[];
  onSubmit?: (data: unknown) => void;
}

export default function GeneratedComponent({
  city = "San Francisco",
  temperature = 68,
  condition = "Partly Cloudy",
  conditionIcon = "⛅",
  humidity = 45,
  windSpeed = "12 mph",
  unit = "F",
  forecast = [
    { day: "Mon", icon: "☀️", high: 72, low: 58 },
    { day: "Tue", icon: "⛅", high: 70, low: 57 },
    { day: "Wed", icon: "☁️", high: 65, low: 55 },
    { day: "Thu", icon: "🌧️", high: 62, low: 52 },
    { day: "Fri", icon: "⛅", high: 68, low: 54 },
  ],
  onSubmit
}: Props) {
  const { motionEnabled } = useMotion();

  const handleCardClick = () => {
    if (onSubmit) {
      onSubmit({ action: "click", component: "WeatherCard", city });
    }
  };

  return (
    <Container maxWidth="sm">
      <MotionKeyframes />
      <Card 
        padding={0} 
        shadow="md"
        border
      >
        <div 
          onClick={handleCardClick}
          role="region"
          aria-label={"Weather information for " + city}
          style={{ 
            cursor: onSubmit ? 'pointer' : 'default',
            overflow: 'hidden',
            borderRadius: 'var(--ggui-radius-lg, 12px)',
          }}
        >
          {/* Branded Header */}
          <Box 
            padding="var(--ggui-spacing-md, 16px)"
            background="var(--ggui-color-primary-50, #f0f9ff)"
          >
            <Stack direction="vertical" gap={4}>
              <Text 
                variant="h3" 
                weight="bold"
                color="var(--ggui-color-primary-900, #0c4a6e)"
              >
                {city}
              </Text>
              <Text 
                variant="caption"
                color="var(--ggui-color-primary-700, #0369a1)"
              >
                {new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}
              </Text>
            </Stack>
          </Box>

          <Box padding="var(--ggui-spacing-lg, 24px)">
            <Stack direction="vertical" gap={24}>

              {/* Main Weather Info */}
              <Row justify="between" align="center">
                <Stack direction="vertical" gap={4}>
                  <Text 
                    style={{ 
                      fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
                      fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                      color: 'var(--ggui-color-text-primary, #111827)',
                      lineHeight: 1,
                    }}
                  >
                    {temperature}°{unit}
                  </Text>
                  <Text 
                    variant="body" 
                    weight="medium"
                    color="var(--ggui-color-text-secondary, #6b7280)"
                  >
                    {condition}
                  </Text>
                </Stack>

                <Text 
                  style={{ 
                    fontSize: '64px',
                    lineHeight: 1,
                    animation: motionEnabled ? animation.scaleIn : 'none',
                  }}
                  aria-hidden="true"
                >
                  {conditionIcon}
                </Text>
              </Row>

              {/* Secondary Details */}
              <Row gap={32} justify="start">
                <Stack direction="vertical" gap={4}>
                  <Text variant="caption" weight="semibold" color="var(--ggui-color-text-secondary, #6b7280)">
                    HUMIDITY
                  </Text>
                  <Text variant="body" weight="bold">
                    {humidity}%
                  </Text>
                </Stack>
                <Stack direction="vertical" gap={4}>
                  <Text variant="caption" weight="semibold" color="var(--ggui-color-text-secondary, #6b7280)">
                    WIND
                  </Text>
                  <Text variant="body" weight="bold">
                    {windSpeed}
                  </Text>
                </Stack>
              </Row>

              <Divider margin={0} />

              {/* 5-Day Forecast Strip */}
              <Stack direction="vertical" gap={12}>
                <Text 
                  variant="caption" 
                  weight="bold" 
                  color="var(--ggui-color-primary-600, #0284c7)"
                  style={{ letterSpacing: '0.05em' }}
                >
                  5-DAY FORECAST
                </Text>
                <Row justify="between" align="center" wrap>
                  {forecast.map((day, index) => (
                    <Stack 
                      key={day.day} 
                      direction="vertical" 
                      align="center" 
                      gap={8}
                      style={{
                        padding: 'var(--ggui-spacing-sm, 8px)',
                        borderRadius: 'var(--ggui-radius-md, 8px)',
                        backgroundColor: index === 0 ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'transparent',
                        minWidth: '60px',
                        flex: '1 1 auto',
                        animation: motionEnabled ? animation.slideInUp : 'none',
                        transition: transition.colors
                      }}
                    >
                      <Text variant="caption" weight="semibold" color="var(--ggui-color-text-secondary, #6b7280)">
                        {day.day}
                      </Text>
                      <Text style={{ fontSize: 'var(--ggui-typography-fontSize-xl, 20px)' }}>
                        {day.icon}
                      </Text>
                      <Stack direction="vertical" gap={0} align="center">
                        <Text variant="caption" weight="bold" color="var(--ggui-color-text-primary, #111827)">
                          {day.high}°
                        </Text>
                        <Text variant="caption" color="var(--ggui-color-text-secondary, #6b7280)">
                          {day.low}°
                        </Text>
                      </Stack>
                    </Stack>
                  ))}
                </Row>
              </Stack>
            </Stack>
          </Box>
        </div>
      </Card>
    </Container>
  );
}

import { useState } from 'react';
import { Container, Card, Stack, Text, Row, Divider } from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string; // e.g., "Mon", "Tue"
  icon: string; // e.g., "☀️", "☁️"
  high: number;
  low: number;
}

interface Props {
  city?: string;
  currentTemperature?: number;
  condition?: string;
  humidity?: number; // percentage
  windSpeed?: number; // e.g., in km/h or mph
  forecast?: ForecastItem[];
  onSubmit?: (data: unknown) => void;
}

export default function GeneratedComponent({
  city = "San Francisco",
  currentTemperature = 22,
  condition = "Partly Cloudy",
  humidity = 65,
  windSpeed = 15, // km/h
  forecast = [
    { day: "Mon", icon: "☀️", high: 23, low: 15 },
    { day: "Tue", icon: "☁️", high: 20, low: 14 },
    { day: "Wed", icon: "🌧️", high: 18, low: 12 },
    { day: "Thu", icon: "☀️", high: 24, low: 16 },
    { day: "Fri", icon: "🌤️", high: 25, low: 17 },
  ],
  onSubmit
}: Props) {
  // Helper to get emoji for weather condition (basic implementation)
  const getWeatherEmoji = (condition: string) => {
    condition = condition.toLowerCase();
    if (condition.includes("sunny")) return "☀️";
    if (condition.includes("cloudy")) return "☁️";
    if (condition.includes("rain")) return "🌧️";
    if (condition.includes("snow")) return "❄️";
    if (condition.includes("storm")) return "⛈️";
    if (condition.includes("partly cloudy")) return "🌤️";
    return "❓"; // Default unknown icon
  };

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-md, 16px)">
      <Card
        padding="var(--ggui-spacing-lg, 24px)"
        shadow="md"
        style={{
          backgroundColor: 'var(--ggui-color-surface, #ffffff)',
          borderRadius: 'var(--ggui-radius-lg, 12px)',
          borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
          borderWidth: '1px',
          borderStyle: 'solid',
        }}
        aria-label={"Weather in " + city}
      >
        <Stack direction="vertical" gap={20}>
          {/* City Header */}
          <Text
            variant="h2"
            align="center"
            style={{
              color: 'var(--ggui-color-primary-800, #075985)',
              fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
            }}
          >
            {city}
          </Text>

          {/* Current Weather */}
          <Stack direction="vertical" align="center" gap={8}>
            <Text
              style={{
                fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
                fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                color: 'var(--ggui-color-text-primary, #111827)',
                lineHeight: '1',
              }}
              aria-label={"Current temperature " + currentTemperature + " degrees Celsius"}
            >
              {currentTemperature}°C
            </Text>
            <Row gap={8} align="center">
              <Text style={{ fontSize: 'var(--ggui-typography-fontSize-xl, 20px)' }}>
                {getWeatherEmoji(condition)}
              </Text>
              <Text
                variant="lg"
                style={{
                  color: 'var(--ggui-color-text-primary, #111827)',
                  fontWeight: 'var(--ggui-typography-fontWeight-medium, 500)',
                }}
                aria-label={"Weather condition: " + condition}
              >
                {condition}
              </Text>
            </Row>
            <Row gap={24} justify="center" style={{ marginTop: 'var(--ggui-spacing-sm, 8px)' }}>
              <Stack direction="vertical" align="center" gap={4}>
                <Text
                  variant="sm"
                  style={{ color: 'var(--ggui-color-text-secondary, #6b7280)' }}
                >
                  Humidity
                </Text>
                <Text
                  weight="semibold"
                  style={{ color: 'var(--ggui-color-text-primary, #111827)' }}
                >
                  {humidity}%
                </Text>
              </Stack>
              <Stack direction="vertical" align="center" gap={4}>
                <Text
                  variant="sm"
                  style={{ color: 'var(--ggui-color-text-secondary, #6b7280)' }}
                >
                  Wind
                </Text>
                <Text
                  weight="semibold"
                  style={{ color: 'var(--ggui-color-text-primary, #111827)' }}
                >
                  {windSpeed} km/h
                </Text>
              </Stack>
            </Row>
          </Stack>

          <Divider margin="var(--ggui-spacing-md, 16px)" />

          {/* 5-Day Forecast */}
          <Stack
            direction="horizontal"
            justify="around"
            wrap={true}
            gap={12}
            style={{
              paddingTop: 'var(--ggui-spacing-sm, 8px)',
              paddingBottom: 'var(--ggui-spacing-sm, 8px)',
            }}
            aria-label="5 day weather forecast"
          >
            {forecast.map((item, index) => (
              <Stack key={item.day + index} direction="vertical" align="center" gap={4}>
                <Text
                  variant="caption"
                  weight="semibold"
                  style={{ color: 'var(--ggui-color-text-secondary, #6b7280)' }}
                >
                  {item.day}
                </Text>
                <Text style={{ fontSize: 'var(--ggui-typography-fontSize-xl, 20px)' }}>
                  {item.icon}
                </Text>
                <Text
                  variant="sm"
                  weight="semibold"
                  style={{ color: 'var(--ggui-color-text-primary, #111827)' }}
                >
                  {item.high}°
                </Text>
                <Text
                  variant="sm"
                  style={{ color: 'var(--ggui-color-text-secondary, #6b7280)' }}
                >
                  {item.low}°
                </Text>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import { useState, useEffect } from 'react';
import { Card, Stack, Row, Text, Container, Box } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  highTemp: number;
  lowTemp: number;
}

interface Props {
  city?: string;
  currentTemp?: number;
  condition?: string;
  icon?: string;
  humidity?: number;
  windSpeed?: number;
  windUnit?: 'mph' | 'kph';
  forecast?: ForecastDay[];
  unit?: 'F' | 'C';
  onSubmit?: (data: unknown) => void;
}

const getWeatherEmoji = (iconName: string): string => {
  const emojiMap: Record<string, string> = {
    'sunny': '☀️',
    'cloudy': '☁️',
    'rainy': '🌧️',
    'stormy': '⛈️',
    'snowy': '❄️',
    'windy': '💨',
    'partly-cloudy': '⛅',
    'foggy': '🌫️',
    'hail': '🌨️',
    'sleet': '🌧️',
  };
  return emojiMap[iconName.toLowerCase()] || '🌤️';
};

export default function WeatherCard({
  city = 'San Francisco',
  currentTemp = 72,
  condition = 'Partly Cloudy',
  icon = 'partly-cloudy',
  humidity = 65,
  windSpeed = 12,
  windUnit = 'mph',
  forecast = [
    { day: 'Mon', icon: 'sunny', highTemp: 75, lowTemp: 62 },
    { day: 'Tue', icon: 'partly-cloudy', highTemp: 73, lowTemp: 61 },
    { day: 'Wed', icon: 'cloudy', highTemp: 68, lowTemp: 58 },
    { day: 'Thu', icon: 'rainy', highTemp: 65, lowTemp: 55 },
    { day: 'Fri', icon: 'sunny', highTemp: 76, lowTemp: 63 },
  ],
  unit = 'F',
  onSubmit,
}: Props) {
  return (
    <Container maxWidth="md">
      <Card
        shadow="md"
        padding="0"
        style={{
          background: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff) 0%, var(--ggui-color-primary-100, #e0f2fe) 100%)',
          overflow: 'hidden',
        }}
      >
        <Stack direction="vertical" gap={0}>
          {/* Header Section */}
          <Box
            padding="var(--ggui-spacing-lg, 24px) var(--ggui-spacing-lg, 24px) var(--ggui-spacing-md, 16px) var(--ggui-spacing-lg, 24px)"
            style={{
              borderBottom: '2px solid var(--ggui-color-primary-200, #bae6fd)',
            }}
          >
            <Text
              variant="caption"
              color="var(--ggui-color-primary-700, #0369a1)"
              weight="semibold"
              style={{
                fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                textTransform: 'uppercase',
                letterSpacing: '0.05em',
              }}
            >
              {city}
            </Text>
          </Box>

          {/* Current Weather Section */}
          <Box
            padding="var(--ggui-spacing-lg, 24px)"
            style={{
              borderBottom: '1px solid var(--ggui-color-primary-150, #b3dffb)',
            }}
          >
            <Stack direction="vertical" gap={16}>
              <Row align="center" gap={20} justify="between">
                <Stack direction="vertical" gap={8} align="start" justify="start">
                  <div
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-4xl, 36px)',
                      fontWeight: 'var(--ggui-typography-fontWeight-bold, 700)',
                      color: 'var(--ggui-color-primary-900, #0c4a6e)',
                      lineHeight: '1.2',
                    }}
                  >
                    {currentTemp}°{unit}
                  </div>
                  <Text
                    color="var(--ggui-color-primary-700, #0369a1)"
                    weight="semibold"
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-lg, 18px)',
                    }}
                  >
                    {condition}
                  </Text>
                </Stack>
                <div
                  style={{
                    fontSize: '72px',
                    lineHeight: '1',
                  }}
                >
                  {getWeatherEmoji(icon)}
                </div>
              </Row>

              {/* Humidity and Wind */}
              <Row gap={24} justify="start">
                <Stack direction="vertical" gap={4} align="start">
                  <Text
                    variant="caption"
                    color="var(--ggui-color-primary-600, #0284c7)"
                    weight="medium"
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-xs, 12px)',
                      textTransform: 'uppercase',
                    }}
                  >
                    Humidity
                  </Text>
                  <div
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-xl, 20px)',
                      fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                      color: 'var(--ggui-color-primary-800, #075985)',
                    }}
                  >
                    {humidity}%
                  </div>
                </Stack>

                <div
                  style={{
                    width: '2px',
                    height: '48px',
                    background: 'var(--ggui-color-primary-200, #bae6fd)',
                  }}
                />

                <Stack direction="vertical" gap={4} align="start">
                  <Text
                    variant="caption"
                    color="var(--ggui-color-primary-600, #0284c7)"
                    weight="medium"
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-xs, 12px)',
                      textTransform: 'uppercase',
                    }}
                  >
                    Wind Speed
                  </Text>
                  <div
                    style={{
                      fontSize: 'var(--ggui-typography-fontSize-xl, 20px)',
                      fontWeight: 'var(--ggui-typography-fontWeight-semibold, 600)',
                      color: 'var(--ggui-color-primary-800, #075985)',
                    }}
                  >
                    {windSpeed} {windUnit}
                  </div>
                </Stack>
              </Row>
            </Stack>
          </Box>

          {/* 5-Day Forecast Section */}
          <Box
            padding="var(--ggui-spacing-lg, 24px)"
          >
            <Stack direction="vertical" gap={12}>
              <Text
                color="var(--ggui-color-primary-700, #0369a1)"
                weight="semibold"
                style={{
                  fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                  textTransform: 'uppercase',
                  letterSpacing: '0.05em',
                }}
              >
                5-Day Forecast
              </Text>

              <Row
                gap={8}
                justify="between"
                wrap
                style={{
                  overflow: 'auto',
                  paddingBottom: 'var(--ggui-spacing-xs, 4px)',
                }}
              >
                {forecast.map((day, index) => {
                  const key = String(index);
                  return (
                    <Box
                      key={key}
                      padding="var(--ggui-spacing-md, 16px) var(--ggui-spacing-sm, 8px)"
                      style={{
                        flex: '1 1 calc(20% - 8px)',
                        minWidth: '90px',
                        background: 'var(--ggui-color-surface, #ffffff)',
                        border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                        borderRadius: 'var(--ggui-radius-lg, 12px)',
                        textAlign: 'center',
                        transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                      }}
                      onMouseEnter={(e) => {
                        const el = e.currentTarget as HTMLElement;
                        el.style.boxShadow = 'var(--ggui-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
                        el.style.borderColor = 'var(--ggui-color-primary-300, #7dd3fc)';
                        el.style.transform = 'translateY(-2px)';
                      }}
                      onMouseLeave={(e) => {
                        const el = e.currentTarget as HTMLElement;
                        el.style.boxShadow = 'none';
                        el.style.borderColor = 'var(--ggui-color-primary-200, #bae6fd)';
                        el.style.transform = 'translateY(0)';
                      }}
                    >
                      <Stack direction="vertical" gap={8} align="center">
                        <Text
                          weight="semibold"
                          color="var(--ggui-color-primary-800, #075985)"
                          style={{
                            fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                          }}
                        >
                          {day.day}
                        </Text>

                        <div style={{ fontSize: '32px', lineHeight: '1' }}>
                          {getWeatherEmoji(day.icon)}
                        </div>

                        <Stack direction="horizontal" gap={4} align="center" justify="center">
                          <Text
                            weight="bold"
                            color="var(--ggui-color-primary-900, #0c4a6e)"
                            style={{
                              fontSize: 'var(--ggui-typography-fontSize-sm, 14px)',
                            }}
                          >
                            {day.highTemp}°
                          </Text>
                          <Text
                            color="var(--ggui-color-primary-500, #0ea5e9)"
                            style={{
                              fontSize: 'var(--ggui-typography-fontSize-xs, 12px)',
                            }}
                          >
                            {day.lowTemp}°
                          </Text>
                        </Stack>
                      </Stack>
                    </Box>
                  );
                })}
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}
